(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["home45"],{"301b":function(n,e,s){"use strict";s.r(e);var o=function(){var n=this,e=n.$createElement,o=n._self._c||e;return o("markdown",{attrs:{source:s("f5d9")}})},r=[],t=s("2877"),d={},a=Object(t["a"])(d,o,r,!1,null,null,null);e["default"]=a.exports},f5d9:function(n,e){n.exports='### MongoDB创建用户\n\n 1.创建管理员\n ```s\n # 创建（切换到）admin数据库\n use admin\n # 创建一个帐号\n db.createUser({user:"admin",pwd:"admin",roles:["root"]})\n\n ```\n 2.授权认证\n ```s\n # 对帐号进行认证\n db.auth("admin","admin")\n ```\n 3.给使用的数据库添加用户\n ```s\n# 创建（切换到）test数据库\n use test\n # 给test数据库创建一个用户\n db.createUser({user:"root",pwd:"123456",roles:[{role:"dbOwner",db:"test"}]})\n ```\n4.通过--auth启动mongoDB\n ```s\n mongod -f /Users/zhangyu/server/mongo/etc/mongo.conf --auth\n ```\n\n ### MongoDB基本语法\n ![avatar](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/mongo/mgdb.png)\n + 插入文档\n + 更新文档\n + 删除文档\n + 查询文档\n\n```s\n# 查看数据库\nshow dbs\n# 创建数据库\nuse demo\n# 创建一个集合（表）\ndb.createCollection("user")\n# 创建一个集合（表），并插入一条数据\ndb.users.insert({id:123,name:"hello"})\n# 删除一个集合\ndb.user.drop()\n# 查看集合（表）\nshow conllections\n# 删除数据库\ndb.dropDatabase()\n# 查看数据库\ndb.user.find() # db.user.find().pretty() (格式化)\n# 查询第一条数据\ndb.user.findOne()\n# 更新一条数据\ndb.user.update({userName:"jack"},{$set:{userAge:30}})\n# 更新一条子文档\ndb.user.update({userName:"jack"},{$set:{"class.name":\'baidu-test\'}})\n# 查询文档\ndb.user.find({userName:\'jack\'})\n# 查询子文档\ndb.user.find({\'class.name\':\'baidu\'})\n# 查询年龄大于40的文档\ndb.user.find({userAge:{$gt:40}})\n# 查询年龄小于40的文档\ndb.user.find({userAge:{$lt:40}})\n# 查询年龄等于40的文档\ndb.user.find({userAge:{$eq:40}})\n# 查询年龄大于等于40的文档\ndb.user.find({userAge:{$gte:40}})\n# 删除一条文档\ndb.user.remove({userId:101})\n```\n### 表数据设计和插入\n\n1.手动插入\n```s\n# 创建数据库db_demo\nuse db_demo\n# 创建goods集合（表），并插入一条数据\ndb.goods.insert({"id":\'1001\',name:\'zhangsan\',address:\'深圳\'})\n```\n2.文件导入\n```s\n# 创建一个空集合\ndb.createCollection("users")\n# 用客户端工具将数据文件导入即可\n用mongohub客户端导入数据\n```\n3.用MongoDB终端进行导入\n```s\n# db_demo是数据库名称\n# users是集合名称（表）\n# /Users/zhangyu/Desktop/dumall-users.是要导入的文件\b的目录\nmongoimport -d db_demo -c users --file /Users/zhangyu/Desktop/dumall-users.\n```\n\n### 搭建基于Express框架的运行环境\n\n安装express generator生成器\n```s\n# 全局安装express-generator生成器\nnpm install -g express-generator\n# 查看express版本\nexpress --version\n```\n通过生成器自动创建项目\n```s\n# 生成一个项目\nexpress server\n```\n配置分析\n```s\n# express默认使用jade，可以修改成html\napp.set(\'views\', path.join(__dirname, \'views\'));\napp.engine(\'.html\',ejs.__express);\napp.set(\'view engine\', \'html\');\n```\n\n### Node的启动和调试方式\n\n通过node命令启动\n```s\nnode server/bin/www\n```\npm2启动\n```s\n# 全局安装pm2 \nnpm install pm2 -g\n# 启动服务\npm2 start server/bin/www\n# 停掉服务\npm2 stop server/bin/www\n# 停掉所有服务\npm2 stop all\n# 查看启动的服务\npm2 list\n# 查看日志\npm2 log\n```\n\n### 基于Express开发后台接口\n\n安装Mongose\n```s\n# npm方式安装\nnpm install mongoose --save \n# yarn 方式安装\nyarn add mongoose\n```\n创建model\n```js\n// 获取mongoose对象\nvar mongoose = require(\'mongoose\');\n// 获取Schema对象\nvar Schema = mongoose.Schema;\n// 创建一个Schema\nvar produtSchema = new Schema({\n  "productId": {\n    type: String\n  },\n  "productName": String,\n  "salePrice": Number,\n  "productNum": Number,\n  "checked": String,\n  "productImage": String\n});\n// 导出Schema,并关联goods表\nmodule.exports = mongoose.model(\'Good\', produtSchema);\n```\n创建路由\n```js\nvar express = require(\'express\');\nvar router = express.Router();\nvar mongoose = require(\'mongoose\');\nvar Goods = require(\'../models/goods\');\n//连接MongoDB数据库\nmongoose.connect(\'mongodb://127.0.0.1:27017/dumall\');\n// connected 链接成功\nmongoose.connection.on("connected", function () {\n  console.log("MongoDB connected success.")\n});\n// error 链接失败\nmongoose.connection.on("error", function () {\n  console.log("MongoDB connected fail.")\n});\n// disconnected 断开链接\nmongoose.connection.on("disconnected", function () {\n  console.log("MongoDB connected disconnected.")\n});\n// 创建路由\nrouter.get(\'/\', function (req, res, next) {\n  Goods.find({}, function (err, doc) {\n    if (err) {\n      res.json({\n        status: \'1\',\n        msg: err.message\n      })\n    } else {\n      res.json({\n        status: \'0\',\n        msg: \'ok\',\n        result: {\n          count: doc.length,\n          list: doc\n        }\n      })\n    }\n  })\n});\nmodule.exports = router;\n```\n[范例](#/home/expressapi)'}}]);